insert into projects (name, slug, category, short_description, story, founder_name, start_year, location, whatsapp, instagram, featured, main_image, gallery)
select name, slug, category, short_description, story, founder_name, start_year, location, whatsapp, instagram, featured, main_image, gallery
from (values
('Puerto Creativo Magdalena','puerto-creativo-magdalena','Cultura','Laboratorio ciudadano para memoria ribereña.','Jóvenes narran su barrio con cámaras, podcast y escritura.','Laura Castaño',2021,'Centro','+573001112233','@puertocreativomagdalena',true,'https://images.unsplash.com/photo-1500530855697-b586d89ba3ee',array['https://images.unsplash.com/photo-1492684223066-81342ee5ff30']),
('Café Estación Dorada','cafe-estacion-dorada','Gastronomía','Café de origen caldense y noches de lectura.','Punto de encuentro para viajeros, comerciantes y creadores.','Andrés Ríos',2019,'Las Ferias','+573004445566','@cafeestaciondorada',true,'https://images.unsplash.com/photo-1509042239860-f550ce710b93',array['https://images.unsplash.com/photo-1442512595331-e89e73853f31']),
('Ribera Bike Tours','ribera-bike-tours','Turismo','Rutas en bicicleta por paisajes ribereños.','Recorridos seguros para mirar La Dorada con otros ojos.','Natalia Gómez',2020,'Malecón','+573007778899','@riberabiketours',true,'https://images.unsplash.com/photo-1485965120184-e220f721d03e',array['https://images.unsplash.com/photo-1517649763962-0c623066013b']),
('Aulas del Río','aulas-del-rio','Educación','Refuerzo escolar y lectura en barrios ribereños.','Voluntarios acompañan a niños y familias con mentorías.','Mónica Salazar',2018,'Victoria Real','+573009991122','@aulasdelrio',false,'https://images.unsplash.com/photo-1509062522246-3755977927d7',array['https://images.unsplash.com/photo-1497633762265-9d179a990aa6']),
('Mercado Verde La Dorada','mercado-verde-la-dorada','Agro','Red de productores rurales y canastas frescas.','Conecta fincas cercanas con hogares y restaurantes.','Jorge Ramírez',2022,'Plaza de Mercado','+573002224455','@mercadoverdeladorada',true,'https://images.unsplash.com/photo-1488459716781-31db52582fe9',array['https://images.unsplash.com/photo-1464226184884-fa280b87c399']),
('Taller Mangle Diseño','taller-mangle-diseno','Moda','Prendas frescas inspiradas en el río y el puerto.','Diseño local con costureras de barrio.','Camila Yepes',2023,'Av. de los Estudiantes','+573005556677','@tallermangle',false,'https://images.unsplash.com/photo-1496747611176-843222e1e57c',array['https://images.unsplash.com/photo-1529139574466-a303027c1d8b']),
('Conecta Dorada Tech','conecta-dorada-tech','Tecnología','Comunidad para programación y herramientas digitales.','Aprendizaje práctico para resolver problemas locales.','Felipe Arango',2021,'Biblioteca Municipal','+573006667788','@conectadoradatech',true,'https://images.unsplash.com/photo-1516321318423-f06f85e504b3',array['https://images.unsplash.com/photo-1498050108023-c5249f4df085']),
('Casa Tambora','casa-tambora','Arte','Escuela independiente de percusión y danza.','Procesos de iniciación artística para todas las edades.','Óscar Molina',2017,'Barrio Corea','+573008889900','@casatambora',false,'https://images.unsplash.com/photo-1514525253161-7a46d19cd819',array['https://images.unsplash.com/photo-1460723237483-7a6dc9d0b212']),
('Manos Doradas Fundación','manos-doradas-fundacion','Impacto Social','Acompañamiento a adultos mayores.','Jornadas barriales y redes de cuidado.','Elena Patiño',2016,'Renán Barco','+573003331144','@manosdoradas',true,'https://images.unsplash.com/photo-1544027993-37dbfe43562a',array['https://images.unsplash.com/photo-1517048676732-d65bc937f952']),
('Cancha Viva','cancha-viva','Deporte','Torneos formativos con convivencia.','Recupera espacios deportivos para formar liderazgo.','Diego Sánchez',2020,'Unidad Deportiva','+573001234567','@canchaviva',false,'https://images.unsplash.com/photo-1526232761682-d26e03ac148e',array['https://images.unsplash.com/photo-1431324155629-1a6deb1dec8d']),
('La Ruta del Bocachico','la-ruta-del-bocachico','Gastronomía','Experiencia culinaria ribereña.','Restaurantes tradicionales y relatos de pescadores.','Rosa Beltrán',2022,'Malecón','+573004567890','@rutadelbocachico',true,'https://images.unsplash.com/photo-1559847844-5315695dadae',array['https://images.unsplash.com/photo-1543352634-a1c51d9f1fa7']),
('Editorial Puerto Sol','editorial-puerto-sol','Cultura','Sello independiente de crónicas y fanzines.','Publica autores locales en tirajes cortos.','Santiago Núñez',2023,'Centro Cultural','+573009876543','@editorialpuertosol',false,'https://images.unsplash.com/photo-1495020689067-958852a7765e',array['https://images.unsplash.com/photo-1519682337058-a94d519337bc']),
('BioRibera Bienestar','bioribera-bienestar','Bienestar','Yoga y salud preventiva en espacios verdes.','Encuentros de autocuidado al amanecer.','Valentina Mora',2021,'Parque Santander','+573007654321','@bioribera',false,'https://images.unsplash.com/photo-1506126613408-eca07ce68773',array['https://images.unsplash.com/photo-1545389336-cf090694435e']),
('Logística Puerto Norte','logistica-puerto-norte','Industria','Soluciones logísticas para pequeños comerciantes.','Optimiza rutas y entregas para negocios locales.','Hernán Mejía',2020,'Zona Industrial','+573002468135','@puertonorte',false,'https://images.unsplash.com/photo-1494412651409-8963ce7935a7',array['https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d']),
('Comercio Vivo Centro','comercio-vivo-centro','Comercio','Red de tiendas familiares del centro.','Vitrinas colectivas y rutas de compra local.','Patricia León',2019,'Centro','+573001357924','@comerciovivocentro',true,'https://images.unsplash.com/photo-1441986300917-64674bd600d8',array['https://images.unsplash.com/photo-1472851294608-062f824d29cc'])
) as v(name,slug,category,short_description,story,founder_name,start_year,location,whatsapp,instagram,featured,main_image,gallery)
on conflict (slug) do nothing;

insert into stories (title, slug, author, category, cover_image, excerpt, content, reading_time, featured)
select 'Historia demo ' || g, 'historia-demo-' || g, 'Redacción Hecho', (array['Crónicas','Entrevistas','Cultura','Historia local','Emprendimiento','Comunidad'])[1 + (g % 6)], 'https://images.unsplash.com/photo-1500530855697-b586d89ba3ee', 'Relato editorial sobre personas y proyectos de La Dorada.', 'Contenido semilla para una historia local enriquecida.', 4 + (g % 6), g <= 4 from generate_series(1,10) g on conflict (slug) do nothing;

insert into podcast_episodes (title, slug, guest_name, category, summary, spotify_url, youtube_url, highlights)
select 'Episodio ' || g || ': Voces que hacen ciudad', 'voces-que-hacen-ciudad-' || g, 'Invitado local ' || g, (array['Cultura','Emprendimiento','Turismo','Tecnología'])[1 + (g % 4)], 'Conversación sobre creación local y comunidad.', 'https://open.spotify.com/embed/episode/0', 'https://www.youtube.com/embed/dQw4w9WgXcQ', array['Hacer ciudad empieza por escuchar.','La colaboración reduce distancias.'] from generate_series(1,8) g on conflict (slug) do nothing;

insert into events (title, slug, date, time, location, organizer, category, description, whatsapp, external_link)
select 'Evento comunitario ' || g, 'evento-comunitario-' || g, current_date + (g || ' days')::interval, '17:00', (array['Malecón','Parque Santander','Biblioteca Municipal','Plaza de Mercado'])[1 + (g % 4)], 'Hecho en La Dorada', (array['Cultura','Comercio','Educación','Deporte'])[1 + (g % 4)], 'Actividad abierta para encontrarse, aprender y celebrar la ciudad.', '+573001112233', 'https://hechoenladorada.co' from generate_series(1,10) g on conflict (slug) do nothing;

insert into indicators (title, value, category, description, source)
select (array['Población estimada','Empresas registradas','Visitantes mensuales','Procesos culturales','Instituciones educativas'])[1 + (g % 5)], (array['78.000','3.240','+12%','46','28'])[1 + (g % 5)], (array['Población','Empresas','Turismo','Cultura','Educación'])[1 + (g % 5)], 'Indicador demo editable desde el panel administrador.', 'Actualizar con fuente oficial' from generate_series(1,20) g;

insert into opportunities (title, category, description, contact_name, contact_phone, contact_email, status)
select (array['Buscamos barista','Voluntarios para lectura','Proveedor de empaques','Socio para ruta turística','Diseñador freelance'])[1 + (g % 5)], (array['Ofrezco empleo','Voluntariado','Busco proveedor','Busco socio','Ofrezco servicios'])[1 + (g % 5)], 'Publicación comunitaria moderada para conectar necesidades y talentos locales.', 'Equipo local', '+573001112233', 'hola@hechoenladorada.co', case when g % 3 = 0 then 'Pendiente'::content_status else 'Publicada'::content_status end from generate_series(1,10) g;
